patches.original_code:
/**
* Determines whether {@code n} is the FUNCTION node in a global function
* declaration.
*/
private boolean isPrototypePropertyAssign(Node assign) {
  Node n = assign.getFirstChild();
  if (n != null && NodeUtil.isVarOrSimpleAssignLhs(n, assign)
      && n.getType() == Token.GETPROP
      ) {
    // We want to exclude the assignment itself from the usage list
    boolean isChainedProperty =
        n.getFirstChild().getType() == Token.GETPROP;

    if (isChainedProperty) {
      Node child = n.getFirstChild().getFirstChild().getNext();

      if (child.getType() == Token.STRING &&
          child.getString().equals("prototype")) {
        return true;
      }
    }
  }

  return false;
}

patches.fixed_method:
private boolean isPrototypePropertyAssign(Node assign) {
  Node n = assign.getFirstChild();
  if (n != null && NodeUtil.isVarOrSimpleAssignLhs(n, assign)
      && n.getType() == Token.GETPROP
      ) {
    // Traverse the GETPROP chain to find the last child
    while (n.getType() == Token.GETPROP) {
      n = n.getLastChild();
    }
    // Check if the last child is a STRING with the value 'prototype'
    if (n.getType() == Token.STRING && n.getString().equals("prototype")) {
      return true;
    }
  }
  return false;
}
